is.loadedChild = this.childrenArr.concat(this.loadedChild)\n\t\t\t\t\t} else {\n\t\t\t\t\t\tthis.loadedChild = this.loadedChild.concat(this.childrenArr)\n\t\t\t\t\t}\n\t\t\t\t\tconst usageData = this.isBefore ? this.loadedChild : this.childrenArr;\n\t\t\t\t\tusageData.forEach((item, index) => {\n\t\t\t\t\t\tthis.getWaterfallInfo(item.height, (res) => {\n\t\t\t\t\t\t\titemGap = res.itemGap\n\t\t\t\t\t\t\t// #ifdef APP-NVUE\n\t\t\t\t\t\t\titem.aniTransForm(res.x, res.y)\n\t\t\t\t\t\t\titem.transform = `translate(${res.x}px,${res.y}px)`\n\t\t\t\t\t\t\t// #endif\n\t\t\t\t\t\t\t// #ifndef APP-NVUE\n\t\t\t\t\t\t\titem.transform = `translate3d(${res.x}px,${res.y}px,0)`\n\t\t\t\t\t\t\t// #endif\n\t\t\t\t\t\t\tsetTimeout(() => {\n\t\t\t\t\t\t\t\titem.isShow = true\n\t\t\t\t\t\t\t}, 20)\n\t\t\t\t\t\t})\n\t\t\t\t\t})\n\t\t\t\t\tthis.setWaterfallHeight(itemGap)\n\t\t\t\t\tthis.childrenArr = []\n\t\t\t\t\tthis.loadedArr = []\n\t\t\t\t\tthis.$emit('end', {})\n\t\t\t\t}\n\t\t\t}\n\t\t}\n\t}\n</script>\n\n<style scoped>\n\t.fui-waterfall__wrap {\n\t\t/* #ifndef APP-NVUE */\n\t\twidth: 100%;\n\t\tbox-sizing: border-box;\n\t\t/* #endif */\n\t\tposition: relative;\n\t\t/* #ifdef APP-NVUE */\n\t\tflex: 1;\n\t\t/* #endif */\n\t}\n</style>","import Component from 'F:/MyGithub/myself-acgi-mpweixin/src/components/firstui/fui-waterfall/fui-waterfall.vue'\nwx.createComponent(Component)"],"names":["uni"],"mappings":";;AAQC,MAAK,YAAU;AAAA,EACd,MAAM;AAAA,EACN,OAAO,CAAC,QAAQ,KAAK;AAAA,EACrB,OAAO;AAAA,IACN,WAAW;AAAA,MACV,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AAAA,IACD,QAAQ;AAAA,MACP,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AAAA,IACD,SAAS;AAAA,MACR,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AAAA,IACD,UAAU;AAAA,MACT,MAAM,CAAC,QAAQ,MAAM;AAAA,MACrB,SAAS;AAAA,IACT;AAAA,IACD,UAAU;AAAA,MACT,MAAM;AAAA,MACN,SAAS;AAAA,IACV;AAAA,EACA;AAAA,EACD,UAAU;AACT,WAAO;AAAA,MACN,WAAW;AAAA,IACZ;AAAA,EACA;AAAA,EACD,OAAO;AACN,WAAO;AAAA,MACN,QAAQ;AAAA,MACR,WAAW;AAAA,MACX,YAAY;AAAA,MACZ,aAAa;AAAA,MACb,MAAM;